import sailpoint.object.IdentityRequest;
import sailpoint.api.IdIterator;
import sailpoint.object.Application;
import sailpoint.object.IdentityRequest.CompletionStatus;
import sailpoint.object.WorkItem.State;
import sailpoint.object.ApprovalItem.ProvisioningState;
import sailpoint.object.*;


log.error("field value : "+value);
List list = new ArrayList();

Application application = context.getObjectById(Application.class,value);


String application_name = application.getName();
Filter filter = Filter.eq("executionStatus","Executing");
QueryOptions qo = new QueryOptions();
qo.add(filter);
//get particular application filtered data
Iterator iterator = context.search(IdentityRequest.class,qo,"id");
IdIterator idIterator = new IdIterator(context, iterator);
if(idIterator != null){

while(idIterator.hasNext()) {

Object unKnownID = idIterator.next();
String id = (String) unKnownID;
IdentityRequest identityRequest=context.getObjectById(IdentityRequest.class,id);
String iden_req_name  = identityRequest.getName();

Filter filter =  Filter.eq("identityRequestId",iden_req_name);
QueryOptions qo = new QueryOptions();
qo.add(filter);
log.error("executed");
Iterator iteratorQuery = context.search("sql:select id from identityiq8_3.spt_work_item_archive where EXTRACTVALUE(attributes, '//ApprovalItem/@application') ='"+application_name+"'  and EXTRACTVALUE(attributes, '//ApprovalItem/@state') = 'Finished'",null,null);
if(iteratorQuery != null){

while(iteratorQuery.hasNext()) {
String row = iteratorQuery.next();
log.error("id-----"+row);
list.add(Filter.eq("id",row));
//Object Work_item_archive = iteratorQuery.next();
//log.error("WorkItemArchive object ----"+row[0]);
}
}
}
}

if(list.size() > 0){
log.error("added into the list");
Filter filter = Filter.or(list);
queryOptions.addFilter(filter);
return queryOptions;
}
else{
log.error("no values in list");
Filter filter = Filter.eq("name","abcdefghij");
queryOptions.addFilter(filter);
return queryOptions;
}
